import json
from pathlib import Path

ROOT = Path(__file__).resolve().parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    if p.exists():
        return json.loads(p.read_text())
    return {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

NEW = {
  "23": {
    "1": "<p>The opening — <em>wᵉḏāwid zāqēn wāśāḇaʿ yāmîm wayyamleḵ ʾet šᵉlōmōh ḇᵉnô ʿal yiśrāʾēl</em>, &lsquo;when David was old and full of days he made Solomon his son king over Israel&rsquo; — sets this chapter within the Chronicler&rsquo;s account of David&rsquo;s institutional preparations for the temple that he could not himself build. The phrase <em>zāqēn wāśāḇaʿ yāmîm</em> (old and satisfied with days) echoes the same formula used for Abraham (Gen 25:8) and Isaac (Gen 35:29), marking the patriarchal quality of David&rsquo;s old age. Unlike 1-2 Kings, which narrate the political machinations surrounding Solomon&rsquo;s succession (Adonijah&rsquo;s bid, Joab&rsquo;s death), Chronicles presents a serene transfer of power focused entirely on temple preparation.</p>",
    "2": "<p>The assembly — all the princes of Israel with the priests and Levites — mirrors the covenant-renewal assemblies of Deuteronomy and Joshua. The Chronicler uses such gatherings consistently to frame David&rsquo;s institutional acts as covenant events involving all Israel (cf. 1 Chr 11:1; 13:2-4; 15:3; 28:1). The inclusion of &lsquo;the priests and the Levites&rsquo; alongside the civil princes signals that what follows is sacral legislation, not merely administrative reorganization. In Chronicles&rsquo; ecclesiology, the people of Israel are constituted as a worshipping community, and its leadership structure — civil and cultic together — gathers around that vocation.</p>",
    "3": "<p>The Levitical census — <em>wayyissāpᵉrû halewyim miben šᵉlōšîm šānāh wāmāʿlāh wayhî misprām lᵉgulgelōtām liḇnê hazzāḵār šᵉlōšîm wᵉšmōnāh ʾālep</em>, 38,000 Levites from age 30 upward — follows the census requirement of Num 4:3 for the wilderness period. The age of 30 was set for the wilderness to ensure physical capability for carrying the tabernacle&rsquo;s heavy components. The Chronicler notes this census as a baseline before explaining (v24-27) the shift to age 20, a modification David makes on the rationale that the tabernacle need no longer be carried now that YHWH has given Israel rest. The number 38,000 belongs to the Chronicler&rsquo;s idealized picture of the Davidic era&rsquo;s abundant resources for temple service.</p>",
    "4": "<p>The allocation of the 38,000 Levites — 24,000 for oversight of the temple work (<em>lᵉnṣaḥ ʿal mᵉleʾḵet bêt YHWH</em>), 6,000 as officers and judges, 4,000 as gatekeepers, and 4,000 as musicians (v5) — reflects a comprehensive institutionalization of Levitical functions. The 6,000 as officers (<em>šōṭᵉrîm</em>) and judges (<em>šōpᵉṭîm</em>) reflects the Levitical judicial role rooted in Deut 17:8-13, where difficult legal cases go to the Levitical priests. Chronicles elsewhere (26:29; 2 Chr 19:8-11) confirms that Levites served in administrative and judicial capacities alongside their cultic duties. The fourfold division formalizes what had been more fluid in the Mosaic period.</p>",
    "5": "<p>The 4,000 musicians — <em>wᵉʾarbaʿat ʾălāpîm mᵉhallᵉlîm laYHWH bakkᵉlîm ʾăšer ʿāśîtî lᵉhallēl</em>, &lsquo;4,000 offering praise to YHWH with the instruments I made for praise&rsquo; — attributes the musical instruments to David&rsquo;s own invention. Amos 6:5 refers to David as one who &lsquo;invented for themselves instruments of music like David,&rsquo; and the Chronicler amplifies this tradition: David is the architect of Israel&rsquo;s worship music. The development of organized temple music is a distinctive emphasis of Chronicles; by contrast, the Samuel-Kings corpus barely mentions it. This emphasis reflects the Chronicler&rsquo;s post-exilic context, in which the Levitical singers (Asaph, Heman, Jeduthun guilds) were prominent Second Temple institutions whose Davidic mandate the Chronicler establishes.</p>",
    "6": "<p>The tribal genealogy of the Levites — Gershon, Kohath, Merari — follows the threefold Levitical structure established in Exod 6:16-19 and elaborated in Num 3-4. Each of the three clans had distinct wilderness duties: Kohathites carried the sanctuary&rsquo;s most holy items (ark, table, lampstand), Gershonites carried the fabric coverings, Merarites carried the structural frames. In the temple era these distinctions of transport are superseded by functional divisions of music, gatekeeping, and temple support — but the tribal structure is preserved as the organizational framework. The Chronicler&rsquo;s detailed genealogical records throughout chs 1-9 and here serve the post-exilic community&rsquo;s need to establish legitimate descent for those who serve in the Second Temple.</p>",
    "7": "<p>The sons of Gershon — Laadan and Shimei — represent the two main branches of the Gershonite family. The names differ slightly from other genealogical lists in the OT (Num 3:18 names Libni and Shimei as Gershon&rsquo;s sons), a variation the Chronicler&rsquo;s genealogical tradition preserves without harmonizing. Such variations throughout 1 Chr 1-9 reflect the use of multiple source documents with differing family traditions. The Gershonite clans are assigned praise responsibilities (v6 implies) consonant with their wilderness role of carrying the tabernacle coverings that formed its outer visible glory.</p>",
    "8": "<p>The three sons of Laadan — Jehiel as chief, Zetham, and Joel — head the first Gershonite branch. Jehiel&rsquo;s descendants appear later (26:21-22) as responsible for the treasuries of the house of YHWH, indicating that Levitical roles were hereditary within sub-clans. The Chronicler&rsquo;s detailed genealogy of even minor family groups reflects his conviction that every Levitical position, however routine, is rooted in covenant history and requires legitimate descent. Post-exilic returnees needed precisely this kind of genealogical anchor (cf. Ezra 2:59-63, where those who could not prove their priestly descent were excluded from the priesthood).</p>",
    "9": "<p>The three sons of Shimei — Shelomoth, Haziel, and Haran — are identified as &lsquo;the heads of the fathers of Laadan.&rsquo; The apparent confusion of assigning these as sons of Shimei but &lsquo;heads of the fathers of Laadan&rsquo; likely reflects a complex genealogy in which Shimei&rsquo;s line served in the leadership roles of the broader Laadan/Libni branch. The Chronicler does not always harmonize such genealogical tensions, suggesting use of multiple source documents with overlapping traditions. The presence of Shelomoth (a name meaning &lsquo;peace-full&rsquo; or &lsquo;complete&rsquo;) in Levitical lists is particularly frequent — several distinct individuals carry this name across Chronicles.</p>",
    "10": "<p>The four sons of Shimei — Jahath, Zina (or Zizah, v11), Jeush, and Beriah — represent the second Gershonite branch. The variation between &lsquo;Zina&rsquo; (v10) and &lsquo;Zizah&rsquo; (v11) reflects either scribal variation or a nickname within the tradition. The explicit enumeration of four sons here contrasts with the following verse&rsquo;s note that Jeush and Beriah &lsquo;had not many sons&rsquo; — a detail that explains why they were treated as a single household for administrative purposes. This kind of administrative flexibility in the Levitical system reflects practical governance of family-based cultic assignments.</p>",
    "11": "<p>The note that Jeush and Beriah were &lsquo;reckoned as one father&rsquo;s house in one enrollment&rsquo; because they &lsquo;did not have many sons&rsquo; provides a rare glimpse into the administrative logic of Levitical organization. Family-based service assignments required a minimum household size to constitute an independent administrative unit; when two sub-clans were too small, they were merged for service purposes. This reflects practical management of a complex institution while maintaining the genealogical principle that only legitimate descendants serve. The flexibility also suggests that the system described is not purely ancient but reflects living administrative practice in the Chronicler&rsquo;s period.</p>",
    "12": "<p>The four sons of Kohath — Amram, Izhar, Hebron, Uzziel — are listed here as the second Levitical clan. The Kohathites were the most prestigious of the three Levitical clans in the wilderness period, responsible for carrying the ark, the table, the lampstand, and the altar — the most holy items (Num 4:4-20). Amram&rsquo;s prominence as Moses&rsquo;s and Aaron&rsquo;s father makes the Kohathite-Amramite line foundational to both the Levitical and Aaronic (priestly) genealogies. The Chronicler has already given Kohath&rsquo;s genealogy in detail in 1 Chr 6:1-30; here the list repeats it in the context of the administrative organization David establishes.</p>",
    "13": "<p>The note about Aaron&rsquo;s separation — <em>wayyibbādēl ʾahărōn lᵉhaqḏîšô qōḏeš qāḏāšîm hûʾ ûḇānāyw ʿad ʿôlām lᵉhaqṭîr lipnê YHWH lᵉšārᵉtô ûlᵉḇārēḵ bišmô ʿad ʿôlām</em>, &lsquo;Aaron was set apart to dedicate the most holy things, he and his sons forever, to burn incense before the LORD, to minister to him, and to bless in his name forever&rsquo; — distinguishes the Aaronic priesthood from the broader Levitical service. The verb <em>wayyibbādēl</em> (was separated/set apart) echoes the Priestly theology of distinction and holiness: Aaron&rsquo;s line holds the exclusive right to offer incense, perform the sacrifices, and pronounce the blessing of Num 6:24-26. The &lsquo;forever&rsquo; (ʿôlām) applied twice emphasises the perpetual, unconditional nature of this consecration.</p>",
    "14": "<p>Moses&rsquo;s sons — reckoned among the tribe of Levi but not as priests — illustrate the principle that the Mosaic and Aaronic lines, though from the same family, have distinct vocations. Moses&rsquo;s sons Gershom and Eliezer are subsumed into the general Levitical service, without the priestly privileges Aaron&rsquo;s line received. The Chronicler calls Moses <em>ʾîš hāʾelōhîm</em> (man of God), the same title applied to prophets (Deut 33:1; 1 Kgs 17:18; 2 Kgs 4:7) — suggesting that Moses&rsquo;s unique authority was prophetic rather than priestly, and that his descendants accordingly serve as Levites, not as priests of the altar.</p>",
    "15": "<p>The two sons of Moses — Gershom and Eliezer — carry names that Moses gave them to memorialize key moments of his life: Gershom from <em>gēr šām</em> (&lsquo;a sojourner there,&rsquo; Exod 2:22, reflecting his exile in Midian) and Eliezer from <em>ʾelî ʿezrî</em> (&lsquo;my God is my help,&rsquo; Exod 18:4, reflecting his deliverance from Pharaoh). Name-giving as theological confession is characteristic of Hebrew narrative; these names embed the exodus story in Moses&rsquo;s family tree itself. The names appear in both Exod 18:3-4 and here, providing a genealogical anchor that connects the Levitical organization of David&rsquo;s day to Mosaic origins.</p>",
    "16": "<p>Shebuel, the chief of Gershom&rsquo;s sons, appears also in 23:16&rsquo;s parallel in 26:24 as responsible for the temple treasuries — <em>ûšᵉḇûʾēl ben gēršōm ben mōšeh nāgîd ʿal hāʾôṣārôt</em>. The assignment of Moses&rsquo;s grandson to treasury oversight rather than altar service reinforces the distinction: Mosaic descendants hold positions of honour and significant responsibility but not the priestly prerogatives of Aaron&rsquo;s sons. The name Shebuel (or Shubael, v20 below) means &lsquo;return to God&rsquo; or &lsquo;captive of God&rsquo; — a name with resonance in the exilic context in which Chronicles was likely composed.</p>",
    "17": "<p>Eliezer had only one son, Rehabiah, whose descendants were &lsquo;very many.&rsquo; The Chronicler preserves this demographic contrast as noteworthy: the smaller son-line produced the larger progeny. Rehabiah&rsquo;s name (<em>rᵉḥaḇyāh</em>, &lsquo;YHWH has made room&rsquo; or &lsquo;YHWH has enlarged&rsquo;) is itself a theological statement about divine provision. The verb <em>hirbû lᵉmaʿlāh</em> (&lsquo;became very many&rsquo;) uses the same root as the blessing of fruitfulness (Num 26:54), suggesting providential increase. Rehabiah&rsquo;s descendants are assigned, in 26:25-28, responsibility for the dedicated things — items vowed to YHWH in battle, an honourable Levitical duty.</p>",
    "18": "<p>Shelomith as chief of Izhar&rsquo;s sons — the second Kohathite branch — heads a line that will appear in 26:25-28 in connection with the temple treasuries of dedicated things. The Kohathite sub-clans are consistently assigned oversight of the most precious temple items (since in the wilderness their forebears carried the most holy furnishings). Izhar&rsquo;s branch includes the famous Korah (Num 16) whose rebellion is not mentioned by Chronicles&rsquo; typically positive presentation — the Chronicler focuses on continuity and legitimacy, not on crises that might undermine the Levitical institutions he is validating.</p>",
    "19": "<p>The four sons of Hebron — Jeriah first, Amariah second, Jahaziel third, Jekameam fourth — represent the third Kohathite sub-clan. Their roles appear in 26:31-32: Jeriah&rsquo;s descendants are appointed over the Reubenites, Gadites, and half-tribe of Manasseh &lsquo;for every matter pertaining to God and for the affairs of the king&rsquo; in Transjordan. This administrative extension across tribal lines reflects the comprehensive reach of the Levitical organizational system in the Chronicler&rsquo;s ideal David-era template. The name Jahaziel (&lsquo;God sees&rsquo;) appears multiple times in Chronicles; a Jahaziel son of Zechariah delivers an oracular prophecy to Jehoshaphat in 2 Chr 20:14.</p>",
    "20": "<p>The two sons of Uzziel — Micah first, Isshiah second — head the fourth Kohathite sub-clan. Uzziel was also the name of Aaron&rsquo;s uncle (Exod 6:18), and Mishael and Elzaphan — Uzziel&rsquo;s sons in Lev 10:4 — carried the bodies of Nadab and Abihu from the sanctuary after their death by fire. The Uzzielites&rsquo; role in that grave moment (Lev 10:4-5) gives the clan an early association with maintaining the sanctuary&rsquo;s holiness in crisis. The continuation of their line into the temple era represents the persistence of Kohathite service despite the upheavals of the wilderness period.</p>",
    "21": "<p>The sons of Merari — Mahli and Mushi — head the third and final Levitical clan. The Merarites in the wilderness carried the frames, bars, pillars, and sockets of the tabernacle (Num 4:31-32) — the heavy structural elements. Their role was essential but less glamorous than the Kohathites&rsquo; carrying of holy items. The names Mahli and Mushi (from the root meaning &lsquo;weak&rsquo; or &lsquo;to draw out&rsquo;) carry no obvious theological significance; they are genealogical names preserved in the ancestral records. Mahli&rsquo;s son Eleazar (v22) and Kish (v21, from Mahli&rsquo;s brother Mushi) head the two Merarite sub-branches.</p>",
    "22": "<p>Eleazar son of Mahli died with no sons, only daughters. His daughters married their kinsmen — the sons of Kish, their uncle&rsquo;s line. This note reflects the inheritance principle of Num 27:1-11 (the daughters of Zelophehad): when a man dies without sons, daughters inherit, and the Levirate/kinship marriage with cousins keeps the property within the clan. Applied here to Levitical service, the principle means the Eleazar-Mahli line was absorbed into the Kish-Mushi branch. Chronicles&rsquo; preservation of this detail reflects careful attention to genealogical accuracy: even unusual succession paths (daughters married to cousins) are recorded to maintain the integrity of the Levitical family rolls.</p>",
    "23": "<p>The three sons of Mushi — Mahli, Eder, and Jeremoth — complete the Merarite genealogy. Mushi&rsquo;s sons bear names meaning respectively &lsquo;weak/sick&rsquo; (Mahli, the same name as his grandfather), &lsquo;flock/herd&rsquo; (Eder), and &lsquo;heights&rsquo; (Jeremoth). The reuse of the name Mahli within the Mushi branch (grandfather Merari&rsquo;s son Mahli; great-great-grandson named Mahli) is common in Hebrew genealogical practice, where names cycle within family traditions to honour ancestors. The completion of the Levitical genealogy in vv7-23 sets up the practical administrative arrangements that follow (vv24-32).</p>",
    "24": "<p>The transition — <em>ʾēlleh bᵉnê lēwî lᵉḇêṯ ʾăḇōṯêhem rāʾšê hāʾāḇôt lᵉpquḏêhem bᵉmispar šēmôt lᵉgulgelōtām ʿōśîm hammᵉlāʾḵāh lᵉʿăḇōḏat bêt YHWH miben ʿeśrîm šānāh wāmāʿlāh</em>, &lsquo;from twenty years old and upward&rsquo; — signals the administrative change from the Mosaic age requirement of 30. The Chronicler notes this as a reform made necessary by changed circumstances. The list that preceded it (vv3-23) used age 30 as the starting point (v3); the summary here applies the new threshold of 20. This harmonization of two different numbers reflects the Chronicler&rsquo;s care to present David&rsquo;s Levitical organization as a thoughtful adaptation of Mosaic precedent to new circumstances, not as contradiction of the Torah.</p>",
    "25": "<p>The theological rationale for the change — <em>kî ʾāmar dāwîd hēnîaḥ YHWH ʾelōhê yiśrāʾēl laʿammô wᵉšāḵan bîrûšālaim ʿad ʿôlām</em>, &lsquo;because David said, the LORD God of Israel has given rest to his people and he dwells in Jerusalem forever&rsquo; — invokes the Deuteronomic rest-theology (Deut 12:9-10: &lsquo;you have not yet come to the rest and the inheritance that the LORD your God is giving you... he will give you rest from all your enemies on every side&rsquo;). The promise of rest was conditional on entering the land; the promise of the permanent divine dwelling in Jerusalem is its fulfilment. Since the ark will no longer journey, the heavy-carrying requirements of the wilderness Levites no longer apply, and the age of service can be lowered to gain more years of active ministry from each Levite.</p>",
    "26": "<p>The explicit statement — &lsquo;the Levites shall no longer need to carry the tabernacle or any of the things for its service&rsquo; — marks a watershed in Israel&rsquo;s cultic history. The mobile sanctuary of the wilderness period is replaced by the permanent temple; the Levites shift from porters to servers. This transition reflects the broader theological movement from &lsquo;tent&rsquo; to &lsquo;house&rsquo; that structures 2 Sam 7 / 1 Chr 17: God does not need a house made by human hands (cf. Acts 7:48), but he graciously accommodates Israel&rsquo;s need for a fixed cultic centre. The Levites&rsquo; new role is not lesser but different — from carrying the divine presence to maintaining and serving in its permanent dwelling.</p>",
    "28": "<p>The Levitical duties in the temple — <em>kî miśśᵉmōtān ʿal bᵉnê ʾahărōn laʿăḇōḏat bêt YHWH ʿal hāḥăṣērôt wᵉʿal hallᵉšākôt wᵉʿal ṭāhărôt lᵉḵāl qōḏeš ûmᵉleʾḵet ʿăḇōḏat bêt hāʾelōhîm</em>, &lsquo;for their duty was to assist the sons of Aaron for the service of the house of YHWH, over the courts and the chambers and the purification of all that is holy&rsquo; — articulates the essential distinction: Levites assist, sons of Aaron serve at the altar. The word <em>miśśᵉmōtān</em> (from their post/station) emphasizes assigned position. The courts (<em>ḥăṣērôt</em>), chambers (<em>lᵉšākôt</em>), and purifications (<em>ṭāhărôt</em>) reflect the spatial and ritual complexity of the temple system, requiring a large support staff to maintain the conditions that made priestly service possible.</p>",
    "29": "<p>The specific duties enumerated — showbread, fine flour for grain offerings, unleavened cakes, pan-fried items, all measures of volume and size — reflect the Levitical role in the temple&rsquo;s food-preparation system. The showbread (<em>leḥem happānîm</em>, bread of the presence) was replaced every Sabbath by the priests; its baking and preparation required Levitical assistance. The Merarites are specified in 9:31 as the ones with responsibility for the &lsquo;flat cakes.&rsquo; Levitical families thus held specialized culinary assignments within the temple service, hereditary roles that combined sacred duty with craft skill. The multiple measures mentioned (&lsquo;all measure of size&rsquo;) indicate Levitical involvement in standardizing the quantities required for the daily and festival offerings.</p>",
    "30": "<p>The daily rhythm of Levitical worship — standing every morning and evening to thank and praise YHWH — establishes temple music as a constant, not merely festival, activity. The formula <em>wᵉlaʿămod babbōqer babbōqer lᵉhōdôt ûlᵉhallēl laYHWH wᵉḵēn lāʿāreḇ</em>, &lsquo;to stand every morning to thank and praise YHWH, and likewise at evening&rsquo; — corresponds to the twice-daily tamid (continual) offering of Exod 29:38-42. The Levitical singers frame the sacrificial system with prayer and praise: the offering is never without word, and the word is never without offering. The morning and evening pattern of prayer is reflected in later Jewish practice (shacharit and minchah/maariv) and in early Christian hours of prayer (Acts 3:1; 10:9).</p>",
    "31": "<p>The festival worship obligations — Sabbaths, new moons, and appointed feasts — represent the rhythmic cultic calendar of Leviticus 23. The phrase <em>lᵉhaqrîḇ laYHWH ʿōlôt laYHWH bammišpār kammišpaṭ ʿălêhem tāmîd</em>, &lsquo;to offer burnt offerings to YHWH on the Sabbaths, new moons, and appointed feasts by number according to the ordinance continually&rsquo; — echoes Num 28-29&rsquo;s detailed schedule of public sacrifices. The Levites are responsible for the organization that makes these offerings possible: assisting in the slaughter, maintaining the altar utensils, managing the distribution. The word <em>tāmîd</em> (continually) emphasizes that this is not an optional supplement to daily service but the rhythm of covenant relationship.</p>",
    "32": "<p>The concluding summary — <em>wᵉšāmᵉrû ʾet mišmeret ʾōhel môʿēd wᵉʾet mišmeret haqqōḏeš ûmišmeret bᵉnê ʾahărōn ʾăḥêhem laʿăḇōḏat bêt YHWH</em>, &lsquo;and they shall keep charge of the tent of meeting and the charge of the holy place and the charge of the sons of Aaron their brothers, for the service of the house of YHWH&rsquo; — uses the technical term <em>mišmeret</em> (charge, guard-duty) three times. This term appears repeatedly in Num 3-4 for the Levitical wilderness assignments; here it is applied to the temple context with the same gravity. The three charges — tent of meeting (the tabernacle&rsquo;s continuation in the temple era), the holy place (the sanctuary itself), and the sons of Aaron (supporting the priests) — define the Levites&rsquo; comprehensive assistive role. The chapter ends as it began: with the Levites serving in the house of YHWH under the structure David established.</p>"
  },
  "24": {
    "1": "<p>The divisions of the sons of Aaron — Nadab, Abihu, Eleazar, and Ithamar — repeat the fourfold Aaronic genealogy of Exod 6:23 and Num 3:2. The inclusion of Nadab and Abihu, who died without sons (v2), serves the narrative function of explaining why the priestly lines that actually function come only from Eleazar and Ithamar. This chapter provides the authoritative origin of the 24-course priestly system — one of the most enduring administrative structures in Israelite history, traceable from the Davidic era through the Second Temple period and into the rabbinic period.</p>",
    "2": "<p>The deaths of Nadab and Abihu — <em>wayyāmot nāḏāḇ waʾăḇîhûʾ lipnê ʾăḇîhem ûḇānîm lōʾ hāyû lāhem</em>, &lsquo;Nadab and Abihu died before their father, and had no children&rsquo; — repeats the notice of Num 3:4 and 26:61 without rehearsing the cause (the strange fire of Lev 10:1-2). Chronicles typically omits the Aaronic line&rsquo;s failures: Lev 10 is not narrated in Chronicles, maintaining the idealized picture of priestly service. The theological effect is to present the 24-course system as reaching back to the very beginning of the Aaronic priesthood, untainted by the early crisis. Eleazar and Ithamar as the two surviving sons thus become the twin roots of the entire post-Mosaic priestly institution.</p>",
    "3": "<p>Zadok from Eleazar&rsquo;s line and Ahimelech from Ithamar&rsquo;s line jointly organize the priestly service — <em>wayyiḥallᵉqēm dāwid wᵉṣāḏôq min bᵉnê ʾelʿāzār wʾăḥîmelek min bᵉnê ʾîṯāmār</em>. The Zadokite line (Eleazar) eventually becomes dominant after Solomon dismisses Abiathar (Ithamar&rsquo;s descendant) in 1 Kgs 2:27; but at this point both lines share organizational authority. The Chronicler&rsquo;s naming of Ahimelech son of Abiathar (rather than Abiathar himself) as Ithamar&rsquo;s representative may reflect a complex textual history; 2 Sam 8:17 has a similar inversion. Zadok&rsquo;s association with Eleazar gives his line the genealogical primacy of the eldest surviving Aaronic branch.</p>",
    "4": "<p>The numerical disproportion — Eleazar&rsquo;s line produced 16 chief men while Ithamar&rsquo;s produced only 8 — is given without explanation. The ratio 16:8 = 2:1 reflects Eleazar&rsquo;s genealogical fecundity relative to Ithamar, and it shapes the structure of the 24 lots: 16 from Eleazar and 8 from Ithamar give the 24-course total. The lot system (v5) prevents either line from asserting precedence beyond what the casting of lots — understood as divine decision — establishes. The description of the heads as <em>gibbôrê ḥayil</em> (mighty men of valor, in secular contexts) applied in cultic terms means those with genealogical legitimacy and status within their priestly families.</p>",
    "5": "<p>The lot system — <em>wayyiḥallᵉqûm bᵉgôrālôt ʾēlleh ʿim ʾēlleh</em>, &lsquo;they divided them by lot, these with these&rsquo; — ensures that the organization of the priestly courses is not a product of human preference but of divine disposition. The <em>gôrāl</em> (lot) functions as a theocratic decision-making tool throughout the OT (Josh 18-19 for tribal allotments; Lev 16:8 for the Day of Atonement; Prov 16:33: &lsquo;the lot is cast into the lap, but its every decision is from YHWH&rsquo;). The phrase &lsquo;officers of the sanctuary and officers of God&rsquo; uses the dual title <em>śar qōḏeš wᵉśar hāʾelōhîm</em> to indicate both the institutional and the theological dimensions of priestly office: they administer the earthly institution and serve the heavenly sovereign.</p>",
    "6": "<p>The scribe Shemaiah son of Nethanel, a Levite, records the lots before the king, the officials, Zadok, Ahimelech, and the Levitical family heads — one household taken for Eleazar, then one for Ithamar, alternating. The presence of the royal court, priestly leadership, and Levitical representatives at the lot-casting transforms it into a covenant ceremony of the highest order. The scribal recording of the lots creates the official document that subsequent generations would reference as the authoritative charter of the priestly courses. This document&rsquo;s significance persisted: the 24-course system appears in Luke 1:5 (Zechariah of the division of Abijah) and in the Mishmarot inscriptions found at Caesarea Maritima (c. 4th century CE), listing all 24 courses with their towns — demonstrating the system&rsquo;s survival even after the Temple&rsquo;s destruction.</p>",
    "7": "<p>The first lot fell to Jehoiarib, the second to Jedaiah. These two courses are listed first in Neh 12:6, 19 among those who returned from Babylon, suggesting their prestige. The Maccabean priestly family belonged to the course of Jehoiarib (1 Macc 2:1: Mattathias &lsquo;of the sons of Joarib&rsquo;), giving the first course a particular prominence in Second Temple history. The names of the 24 courses became so embedded in Israelite calendrical consciousness that they were used as chronological markers; the identification of a priestly course told one what week of the year it was, twice over (each course served approximately twice per year on a rotating basis).</p>",
    "8": "<p>The third lot to Harim, the fourth to Seorim. Harim&rsquo;s course is attested in Ezra 2:39 and Neh 7:42 among those returning from exile — 1017 sons of Harim are listed among the lay Israelites in Ezra 2:32, a different Harim family, but the priestly course of the same name also returned (Ezra 2:39: 1017 sons of Harim). The continuity of course names across the exile and return demonstrates the system&rsquo;s remarkable resilience: even after the destruction of the First Temple and the Babylonian deportation, the priestly family organizations maintained enough institutional memory to reconstitute themselves in the Second Temple period.</p>",
    "9": "<p>The fifth lot to Malchijah, the sixth to Mijamin. These courses represent the middle section of the 24-course calendar. Malchijah appears among the priests in Neh 10:3 who sealed the covenant, and a tower of the wall is repaired by sons of Malchijah in Neh 3:14, suggesting the course&rsquo;s involvement in post-exilic Jerusalem&rsquo;s rebuilding. The practical significance of knowing one&rsquo;s course was that it determined when a family was responsible for the temple service — a week of intense activity twice per year, plus participation in the three pilgrimage festivals when all courses served simultaneously.</p>",
    "11": "<p>The ninth lot to Jeshua, the tenth to Shecaniah. The course of Jeshua is attested in Ezra 2:36 — 973 sons of Jeshua of the house of Jedaiah — the largest priestly group returning from exile. This Jeshua (the high priest Joshua son of Jehozadak) led the returning community alongside Zerubbabel (Ezra 2:2; 3:2; Hag 1:1). The prominence of the Jeshua course in the return from exile reflects the endurance of one of the earliest-established priestly families. Shecaniah as the tenth course appears in Neh 12:3 among the post-exilic priestly heads, confirming course continuity across the exile.</p>",
    "12": "<p>The eleventh lot to Eliashib, the twelfth to Jakim. Eliashib the high priest (Neh 3:1; 13:4-9) who rebuilt the Sheep Gate in Jerusalem&rsquo;s wall renovation belonged to the priestly lineage associated with this course name. His controversial later decision to provide Tobiah the Ammonite with a chamber in the temple courts (Neh 13:4-9) represents a tension between the post-exilic community&rsquo;s political relationships and the purity requirements of the temple. The detail that Nehemiah ejected Tobiah&rsquo;s furniture and restored the chamber illustrates how seriously temple boundaries were maintained even when high-priestly authority was compromised.</p>",
    "13": "<p>The thirteenth lot to Huppah, the fourteenth to Jeshebeab. These two courses occupy the midpoint of the 24-division calendar. The name Jeshebeab (perhaps meaning &lsquo;father dwells&rsquo; or &lsquo;sitting with the father&rsquo;) appears only here in the OT. The rarity of attestation for some course names outside 1 Chr 24 suggests that these were smaller or less prominent priestly families whose traces in the historical and prophetic literature are minimal — yet they received their divinely-sanctioned place in the temple calendar through the lot, and their hereditary service was as legitimate as the more prominent courses.</p>",
    "14": "<p>The fifteenth lot to Bilgah, the sixteenth to Immer. Immer is one of the better-attested course names: the prophet Pashur son of Immer (Jer 20:1) was a temple official who struck Jeremiah and put him in stocks — a reminder that the priestly institution included both faithful servants and opponents of the prophetic word. The sons of Immer are listed in Ezra 2:37 (1052 returning from exile) and Neh 7:40, making this one of the larger priestly groups in the post-exilic community. Bilgah appears in Neh 12:5, 18 among the returned priestly heads who sealed the covenant.</p>",
    "15": "<p>The seventeenth lot to Hezir, the eighteenth to Aphses. The name Hezir appears twice in Neh 10:20 (a priestly signer of the covenant) and is associated with one of the most impressive Second Temple-period monuments: a tomb facade in the Kidron Valley east of Jerusalem bears the inscription &lsquo;of the priestly family of Hezir&rsquo; (c. 1st century BCE), identifying the ornate burial as belonging to this ancient course. The monument&rsquo;s Greek-style architecture combined with Hebrew inscription illustrates how priestly families navigated Hellenistic culture while maintaining Jewish identity. The tomb is referred to today as the &lsquo;Tomb of the Sons of Hezir.&rsquo;</p>",
    "16": "<p>The nineteenth lot to Pethahiah, the twentieth to Jehezekel. Pethahiah appears in Neh 11:24 as a royal official to the Persian king for all matters concerning the people — a Levite who bridged the priestly and civil administrative worlds. The name Jehezekel (essentially the same as Ezekiel, meaning &lsquo;God strengthens&rsquo;) is shared with the prophet of the exile, who was himself a priest (Ezek 1:3: &lsquo;among the priests in the land of the Chaldeans&rsquo;). Whether Ezekiel&rsquo;s family belonged to this course is unknown, but his priestly background shapes his vision of the restored temple in Ezek 40-48, which develops many of the organizational principles here established by David.</p>",
    "17": "<p>The twenty-first lot to Jachin, the twenty-second to Gamul. The name Jachin is shared with one of the two bronze pillars of Solomon&rsquo;s temple (1 Kgs 7:21: <em>wayyiqrāʾ ʾet šem hayyāmînî yāḵîn wᵉʾet šem haśśᵉmālî bōʿaz</em>), suggesting the name&rsquo;s association with the temple establishment. Gamul appears only here; its etymology (possibly from <em>gāmal</em>, to deal bountifully or to wean) carries no obvious cultic significance. These two courses, nearly at the end of the 24-division cycle, would serve in the final weeks of the annual priestly rotation, their service structured by the same Davidic charter as those who served first.</p>",
    "18": "<p>The twenty-third lot to Delaiah, the twenty-fourth and final to Maaziah. Delaiah appears in Jer 36:12, 25 as a court official in Jehoiakim&rsquo;s day who &lsquo;urged the king not to burn the scroll&rsquo; of Jeremiah&rsquo;s prophecies — a sympathetic figure at a moment of prophetic crisis. Maaziah as the last course brings the cycle to completion. The completion of 24 courses means that the full priestly calendar covers the entire year in an ordered, divinely-sanctioned sequence. The system was not simply a human administrative convenience but a sacral structure meant to ensure that YHWH&rsquo;s house was never without its ordained servants.</p>",
    "19": "<p>The summary — <em>ʾēlleh pᵉquddātām laʿăḇōḏātām lābôʾ lᵉḇêt YHWH kammišpāṭ bᵉyad ʾahărōn ʾăḇîhem kaʾăšer ṣiwwāhû YHWH ʾelōhê yiśrāʾēl</em>, &lsquo;these were their appointed duties in their service for coming to the house of YHWH according to the procedure commanded of them by Aaron their father, as the LORD God of Israel had commanded him&rsquo; — closes the 24-course register by anchoring it in Mosaic-Aaronic authority. The chain of command runs from YHWH to Aaron to the courses: every course serves not by David&rsquo;s administrative decision alone but by the divine command mediated through Aaron. The Davidic organization is legitimate precisely because it implements and formalizes what YHWH had already commanded.</p>",
    "20": "<p>The extension of the lot-casting to the remaining Levites — beginning with Shubael son of Gershom son of Moses — mirrors the priestly organization just completed with an equivalent Levitical organization. The Chronicler ensures parity: as the sons of Aaron were organized by lot into 24 courses, so the Levites are similarly organized by lot into equivalent functional groups. The Davidic template covers every level of temple service. Shubael (the same as Shebuel of 23:16) as the first Levite named in this supplementary list reflects the prominence of the Mosaic family within the broader Levitical order.</p>",
    "21": "<p>Isshiah as &lsquo;the first&rsquo; of the sons of Rehabiah — Rehabiah being Moses&rsquo;s grandson through Eliezer — represents the continuation of the Mosaic Levitical line. The detail that Rehabiah&rsquo;s sons were &lsquo;very many&rsquo; (23:17) makes Isshiah&rsquo;s identification as &lsquo;first&rsquo; among them significant: he heads a large clan that nonetheless submits to the same lot-based organization as all other Levitical families. The democratic principle of the lot — applied equally to Moses&rsquo;s descendants and those of lesser genealogical prestige — embodies the Levitical ideal that service to YHWH, not family prominence, is the determinative value.</p>",
    "22": "<p>The sons of the Izharites — Shelomoth — and the sons of Shelomoth — Jahath — continue the Kohathite Levitical supplementary list. The Izharites&rsquo; assignments in 26:25-28 involve the dedicated treasuries, items consecrated by David, the commanders, and the military during various campaigns. The inclusion of military-dedicated items in the temple treasury (weapons, spoils of war consecrated to YHWH) reflects the deep integration of Israelite military and cultic life: victories were understood as YHWH&rsquo;s, and their material fruits were therefore owed to YHWH&rsquo;s house.</p>",
    "23": "<p>The sons of Hebron — Jeriah the first, Amariah the second, Jahaziel the third, Jekameam the fourth — repeat the genealogy of 23:19, now in the context of the supplementary lot assignments. The Hebronites&rsquo; role in 26:30-32 is distinctive: they are assigned oversight &lsquo;on the western side of the Jordan&rsquo; and &lsquo;in all the business of YHWH and in the service of the king&rsquo; in Transjordan, connecting cultic and royal administration. The comprehensive reach of the Levitical organization across all Israel&rsquo;s territories — both sides of the Jordan — reflects the universality of the covenant community&rsquo;s worship obligations.</p>",
    "24": "<p>The sons of Uzziel — Michah — and the sons of Michah — Shamir — continue the fourth Kohathite branch. Shamir appears only here; the name (meaning &lsquo;thorn&rsquo; or &lsquo;adamant stone&rsquo;) shares a root with the word used for the hard material of the heart that refuses to respond to prophetic preaching (Ezek 3:9; Zech 7:12). No theological significance attaches to the name in this genealogical context; it is preserved simply as the ancestral record of a Levitical sub-clan. The meticulous inclusion of even minor sub-branch names reflects the Chronicler&rsquo;s conviction that every legitimate Levitical lineage deserves its place in the official record.</p>",
    "25": "<p>Isshiah the brother of Michah — and his sons Zechariah — represent the second Uzzielite branch. The pattern of brothers leading parallel branches within a Levitical clan is consistent throughout chs 23-26: the family is the organizing unit, and the family tree determines both identity and assignment. The name Zechariah (meaning &lsquo;YHWH has remembered&rsquo;) is one of the most common in Chronicles and the post-exilic period generally, reflecting the community&rsquo;s theological emphasis on divine remembrance of the covenant during and after the exile. Zechariah son of Jeberechiah, cited by Isaiah (Isa 8:2) as a witness, may or may not be related to this Levitical Zechariah.</p>",
    "26": "<p>The sons of Merari — Mahli and Mushi — and the sons of Jaaziah — Beno — introduce a figure (Jaaziah) not mentioned in the earlier Merarite genealogy of 23:21-23. This addition has puzzled interpreters: no Jaaziah appears among Merari&rsquo;s sons elsewhere, suggesting either a variant genealogical tradition or a later branch that had developed by the Chronicler&rsquo;s time. The Chronicler&rsquo;s willingness to include Jaaziah without harmonizing him with the earlier list reflects an empirical approach to genealogical sources — multiple traditions are recorded side by side rather than reduced to a single harmonized account.</p>",
    "27": "<p>The sons of Merari by Jaaziah — Shoham, Zaccur, and Ibri — represent a Merarite sub-branch of uncertain genealogical position. The names carry no special theological significance. Their inclusion alongside the main Mahli and Mushi lines reflects the Chronicler&rsquo;s comprehensive genealogical record-keeping: all Levitical claims to temple service, whether from the major lines or minor branches, are documented and legitimated by their inclusion in the official list. The lot-casting that follows (v31) applies equally to these lesser-known names as to the sons of the primary genealogical lines.</p>",
    "28": "<p>Eleazar son of Mahli died with no sons — the same fact noted in 23:22. His branch is absorbed into the broader Merarite family through the marriage of his daughters to Kish&rsquo;s sons (23:22). The repetition of this note here serves the lot-casting narrative: even a line without direct male-line descendants is accounted for, and the provision of Num 27 (daughters inherit in the absence of sons) is applied to Levitical assignments as well. The comprehensive fairness of the system — no branch excluded, no gap in the record — reflects the ideal Davidic organization that the Chronicler presents as the template for legitimate temple service.</p>",
    "29": "<p>Jerahmeel son of Kish — the only son mentioned — represents the absorption of the Eleazar-Mahli Merarite line into the Kish branch through the marriages of 23:22. Jerahmeel (meaning &lsquo;may God show compassion&rsquo; or &lsquo;God is compassion&rsquo;) appears in other genealogical contexts in Chronicles (2:9, 25-41) as a Judahite name; its occurrence here in a Levitical context reflects the name&rsquo;s wide distribution across Israelite genealogies. The name may have been chosen to reflect the providential care of God in preserving the Eleazar line even after its male-line extinction — compassion expressed through the daughters-to-cousins provision.</p>",
    "30": "<p>The sons of Mushi — Mahli, Eder, and Jerimoth — complete the Merarite supplementary list, repeating the genealogy of 23:23. The repetition from ch 23 to ch 24 of several genealogical sections serves a structural purpose in Chronicles: ch 23 establishes the genealogical basis for the Levitical organization, while ch 24 documents the actual lot-casting that distributed the assignments. The genealogy in ch 23 is the identity document; the lot in ch 24 is the assignment document. Together they answer both &lsquo;who are these people?&rsquo; and &lsquo;what are they to do?&rsquo;</p>",
    "31": "<p>The closing summary — lots cast for all Levites, the fathers&rsquo; houses of the chief and his younger brothers alike, before David, Zadok, Ahimelech, and the heads of the priestly and Levitical families — mirrors the priestly lot-casting of vv5-6. The equity principle is explicit: <em>ʾāḥîw haqqāṭōn kaggādôl</em>, &lsquo;the youngest brother equally with the eldest.&rsquo; This equality before the lot reflects the theological principle that YHWH does not show partiality (Deut 10:17; Acts 10:34): the lot determines service, not birth order or family prestige. The priestly and Levitical organization of David thus embodies the same impartial justice that characterizes YHWH himself in his covenant dealings with Israel.</p>"
  },
  "25": {
    "2": "<p>The sons of Asaph — Zaccur, Joseph, Nethaniah, and Asarelah — prophesied under the direction of Asaph their father, himself acting under the king&rsquo;s orders. The verb used for their musical activity is <em>hanibbāʾ</em> (from <em>nābāʾ</em>, to prophesy) — the same verb used for the prophets of the Spirit (Num 11:25-26; 1 Sam 10:5-13; 19:20-24). Temple music is here explicitly classified as prophetic speech: the singers do not merely perform aesthetic compositions but deliver the divine word through song. The Asaph psalms (Pss 50, 73-83) bear this out: Ps 50 is an extended divine oracle; Ps 73-83 deal with theodicy, Israel&rsquo;s history, and divine judgment in terms consistent with prophetic preaching. The Asaphite guild thus occupies the intersection of Levitical service and prophetic vocation.</p>",
    "3": "<p>The sons of Jeduthun — Gedaliah, Zeri, Jeshaiah, Hashabiah, and Mattithiah, with Shimei sometimes read as a sixth — prophesied with the harp &lsquo;in thanksgiving and praise to YHWH.&rsquo; The Jeduthun/Ethan psalms (Ps 39, 62, 77 bear the superscription <em>lîḏûṯûn</em> or <em>ʿal yᵉḏûṯûn</em>) reflect the guild&rsquo;s distinctive character: Ps 77 is a lament that works through historical memory of the exodus to reach confidence; Ps 39 is an individual lament about mortality. The Jeduthun guild evidently specialized in the kind of prophetic music that brought present distress into conversation with divine past acts. The verb <em>hōḏôṯ ûhallēl</em> (thanksgiving and praise) captures the duality of all authentic Levitical music: acknowledging human need while affirming divine faithfulness.</p>",
    "4": "<p>The fourteen sons of Heman — Bukkiah, Mattaniah, Uzziel, Shebuel, Jerimoth, Hananiah, Hanani, Eliathah, Giddalti, Romamtiezer, Joshbekashah, Mallothi, Hothir, Mahazioth — form the largest single musical family. Scholars have noted that the names of the last nine sons (Hananiah through Mahazioth) may be an embedded liturgical poem or prayer when read consecutively: <em>ḥānānî ʾelîyāṯāh giddaltî romamtî ʿezer yôšbᵉqāšāh mallôṯî hôṯîr mahăzîʾôṯ</em> has been read as &lsquo;be gracious to me, O God, exalt my helper; I sit in hardship; give me abundant visions.&rsquo; While this interpretation remains debated, it would make the Heman family&rsquo;s names a devotional text embedded in the genealogical record — a uniquely Hebraic practice of encoding theology in ancestral naming.</p>",
    "5": "<p>The description of Heman as <em>ḥōzēh hammelek bᵉḏiḇrê hāʾelōhîm</em>, &lsquo;the king&rsquo;s seer in the matters of God&rsquo; — uses the word <em>ḥōzēh</em> (seer, one who receives visions), one of the three Hebrew words for prophet (alongside <em>nābîʾ</em> and <em>rōʾeh</em>). Heman is thus both a Levitical musician and a prophetic figure, holding a title equivalent to those given to Gad (2 Sam 24:11) and Asaph (2 Chr 29:30). The note that God gave Heman 14 sons and 3 daughters &lsquo;to exalt his horn&rsquo; — <em>lᵉrôm qeren</em> — uses the imagery of animal power and social honour (cf. Ps 92:10: &lsquo;you have exalted my horn like that of the wild ox&rsquo;). Heman&rsquo;s prominence as seer and musician, blessed with exceptional offspring, marks him as the most distinguished of the three musical guilds&rsquo; founders.</p>",
    "6": "<p>The unifying summary — all three family heads (Asaph, Jeduthun, Heman) and their sons serving in the house of YHWH with cymbals, psalteries, and harps, under their fathers&rsquo; direction, according to the king&rsquo;s order — establishes the dual authority structure of temple music. The fathers are the immediate musical directors (<em>taḥat yᵉḏê ʾăḇîhem</em>); the king is the institutional authority (<em>kammišpaṭ hammelek</em>). This dual accountability — to musical expertise and to royal commission — gives temple music both artistic integrity and political legitimacy. The three instruments mentioned (cymbals, psalteries, harps) appear repeatedly in the Psalter&rsquo;s doxological conclusions (Pss 150:3-5), suggesting that the Levitical instrumentation of David&rsquo;s day shaped the canonical form of Israel&rsquo;s worship poetry.</p>",
    "7": "<p>The total of 288 singers — <em>wayhî misparām ʿim ʾăḥêhem mᵉlummᵉḏê šîr laYHWH kol hammēḇîn māʾtayim šmōnîm ûšmōnāh</em>, &lsquo;and their number along with their brothers who were trained in singing to the LORD, all who were skilful, was 288&rsquo; — is precisely 24 courses × 12 members each. The parallelism with the 24 priestly courses of ch 24 is deliberate: the musicians are organized on the same division-of-twelve model as the priests, giving the musical guild the same structural legitimacy as the Aaronic priesthood. The word <em>mᵉlummāḏ</em> (trained, instructed) indicates that the Levitical singers were not self-taught but formally trained in the craft of temple song — a professional musical institution.</p>",
    "8": "<p>The egalitarian lot-casting — <em>wayyappîlû gôrālôt mišmeret lᵉʿummat kakkāṭōn kaggāḏôl maskîl ʿim talmîḏ</em>, &lsquo;they cast lots for their duties, small and great, teacher alongside student&rsquo; — applies the same democratic principle as the priestly lot of ch 24. The pairing of <em>maskîl</em> (skilled teacher, a term in Psalm superscriptions for a didactic psalm) with <em>talmîḏ</em> (student/disciple) is the only occurrence of the word <em>talmîḏ</em> in the OT outside Isa 8:16. The musical guild had a formal pedagogical structure — masters and apprentices — and the lot applied equally to both. This educational dimension of temple music anticipates the later scribal schools and synagogue learning in which the transmission of sacred texts and sacred music was intertwined.</p>",
    "9": "<p>The first lot — to Joseph son of Asaph, with his brothers and sons, twelve in total — begins the 24-musical-course register. That Joseph rather than Zaccur (the first-named son in v2) receives the first lot underscores the randomness of the lot: seniority of naming does not equal priority of service. The number twelve per course (× 24 courses = 288 total, v7) creates a perfectly regular system: each musical course consisted of a leader and eleven others, likely including both family members and trained associates. The size of twelve per course is consistent with the tribal symbolism of twelve throughout Israel&rsquo;s institutional life.</p>",
    "10": "<p>The third lot to Zaccur — among the sons listed in v2 as first — confirms that the lot reshuffled the order of service relative to genealogical seniority. Zaccur (meaning &lsquo;remembered&rsquo;) is a common name in Chronicles and the post-exilic period; multiple figures bear it in Neh 3:2; 10:12; 13:13. The persistence of the name Zaccur across priestly and Levitical lists suggests a naming tradition within the broader Levitical community. The twelve who serve with Zaccur in the third course represent one of the 24 weekly rotations of the temple music — each course bringing its particular musical and prophetic character to the worship of YHWH&rsquo;s house.</p>",
    "11": "<p>The fourth lot to Izri (a variant of Zeri, v3, from Jeduthun&rsquo;s sons) — with his brothers and sons, twelve — represents the first Jeduthunite course to appear in the lot sequence. The mixing of sons from different guilds (Asaph, Jeduthun, Heman) through the random lot creates a calendar in which the three musical families alternate throughout the year rather than serving in contiguous blocks. This interleaving ensures that the prophetic-musical traditions of all three guilds are woven throughout the annual cycle of temple worship, preventing any one family&rsquo;s approach from dominating the liturgical year.</p>",
    "12": "<p>The fifth lot to Nethaniah (from Asaph&rsquo;s sons, v2) — with twelve — continues the alternating pattern. Nethaniah (meaning &lsquo;YHWH has given&rsquo;) is borne by another prominent figure: Nethaniah the father of Ishmael, who murdered Gedaliah the governor appointed by Babylon (Jer 40:8; 41:1). The name&rsquo;s occurrence in both a musical Levite and a political assassin illustrates how common names spread across very different social and vocational contexts in ancient Israel, with no necessary connection between the individuals.</p>",
    "13": "<p>The sixth lot to Bukkiah (from Heman&rsquo;s sons, v4) — with twelve — brings the first Hemanite course into the sequence. Heman&rsquo;s fourteen sons will appear distributed throughout the 24 courses, giving the Hemanite guild disproportionate representation (14 of 24 courses versus 4 Asaphite and perhaps 6 Jeduthunite). This distribution reflects Heman&rsquo;s unique status as &lsquo;the king&rsquo;s seer&rsquo; (v5) and his exceptional family size — God&rsquo;s gift of 14 sons translated directly into a larger share of the musical calendar. The lot&rsquo;s randomness operates within the constraint of available family heads; Heman&rsquo;s abundance of sons means more lots fall to his line.</p>",
    "14": "<p>The seventh lot to Jesharelah (the Asarelah of v2, with a variant spelling) — the last of Asaph&rsquo;s four sons to appear in the lot sequence. Asaph&rsquo;s four sons thus hold the first, third, fifth, and seventh positions in the 24-course rotation — an even distribution across the first seven slots that may reflect the lot&rsquo;s statistical outcome or a traditional organization shaped by prior practice. The Asaphites&rsquo; four courses give them a musical presence at every quarter of the year, consistent with their role as the guild most directly associated with the royal court and its occasions.</p>",
    "15": "<p>The eighth lot to Jeshaiah (from Jeduthun&rsquo;s sons, v3) — continuing the alternating guild pattern. Jeshaiah (meaning &lsquo;YHWH saves&rsquo;, essentially the same name as Isaiah) is borne by several figures in the post-exilic community: the son of Hananiah who was Zerubbabel&rsquo;s grandson (1 Chr 3:21), and a Levite who returned with Ezra (Ezra 8:19). The name&rsquo;s frequency in the post-exilic period may reflect the community&rsquo;s heightened consciousness of YHWH&rsquo;s salvation at the time of return from Babylon — naming children after the concept of divine deliverance that the exile made vivid.</p>",
    "16": "<p>The ninth lot to Mattaniah (from Jeduthun&rsquo;s sons, v3) — meaning &lsquo;gift of YHWH.&rsquo; A Mattaniah appears prominently in Neh 11:17 and 12:8, 25 as a Levitical singer in post-exilic Jerusalem, specifically as one who &lsquo;led the thanksgiving in prayer.&rsquo; If this is the descendant of the Mattaniah/Jeduthun course, it illustrates the continuity of the Davidic musical organization into the Second Temple period: the same family names, the same roles of thanksgiving leadership, carrying forward across the centuries the temple music David established.</p>",
    "17": "<p>The tenth lot to Shimei — a name associated with the sons of Jeduthun in some textual traditions (v3 has been read as including Shimei as a sixth son). Shimei is one of the most common names in the OT, born by figures ranging from a Benjaminite who cursed David (2 Sam 16:5-13) to multiple Levites throughout Chronicles. The name&rsquo;s meaning (&lsquo;hearing&rsquo; or &lsquo;renowned&rsquo;) makes it a natural choice for a family in which public musical performance was the primary vocation. The universality of the name across tribes and contexts reflects Hebrew naming culture&rsquo;s preference for theophoric or attribute names over purely distinctive identifiers.</p>",
    "18": "<p>The eleventh lot to Azareel (variant of Uzziel in v4, from Heman&rsquo;s sons) — meaning &lsquo;God has helped.&rsquo; The name Azareel appears in Neh 11:13 (a priestly head), 12:36 (a musician in Nehemiah&rsquo;s dedication of the wall), and Ezra 10:41 (one who had married a foreign wife). Its multiple occurrences across the post-exilic community confirm the name&rsquo;s popularity, possibly in connection with the community&rsquo;s sense of divine help (<em>ʿazar</em>) through the trials of exile and return.</p>",
    "19": "<p>The twelfth lot to Hashabiah (from Jeduthun&rsquo;s sons, v3) — meaning &lsquo;YHWH has reckoned&rsquo; or &lsquo;YHWH has esteemed.&rsquo; Hashabiah appears numerous times in Chronicles and Nehemiah: a Merarite Levite appointed over western Jordan affairs (1 Chr 26:30), a ruler of half the district of Keilah in Nehemiah&rsquo;s wall-building (Neh 3:17), a Levite who sealed the covenant (Neh 10:11), and a leader of the Levitical assembly in Neh 12:24. The frequency of this name across Levitical and administrative contexts in the post-exilic period suggests it was particularly popular among Levitical families, perhaps as a statement about YHWH&rsquo;s gracious accounting of covenant faithfulness.</p>",
    "20": "<p>The thirteenth lot to Shubael (variant of Shebuel, from Heman&rsquo;s sons, v4) — the son of Gershom son of Moses, whose treasury oversight is mentioned in 23:16 and 26:24. The return of this name in the 24-course lot list confirms that even the most prominent Levitical sub-clan heads — those associated with the Mosaic lineage — receive their place in the rotation by lot rather than by privilege. The Mosaic prestige of Shubael&rsquo;s line does not exempt it from the democratic equity of the lot-casting; it takes its thirteenth position in the rotation without special precedence.</p>",
    "21": "<p>The fourteenth lot to Mattithiah (from Heman&rsquo;s sons, v4, though a Mattithiah of Shallum is mentioned in 9:31 as responsible for the flat cakes). Mattithiah (&lsquo;gift of YHWH&rsquo;, related to Mattaniah) appears also in Ezra 10:43 as one who had taken a foreign wife, and in Neh 8:4 as one of those who stood beside Ezra at the public reading of the Torah. The Neh 8:4 Mattithiah represents the ideal post-exilic Levitical figure: present at and supporting the public proclamation of God&rsquo;s word, the very function that the temple singers&rsquo; prophetic music had always served.</p>",
    "22": "<p>The fifteenth lot to Jeremoth (from Heman&rsquo;s sons, v4) — meaning &lsquo;heights&rsquo; or &lsquo;swellings.&rsquo; Jeremoth appears in Ezra 10:26-27 among those who had taken foreign wives during the restoration period — a reminder that even Levitical families were not immune to the social pressures that threatened the community&rsquo;s covenant distinctiveness. The Chronicler&rsquo;s presentation of the ideal Davidic temple organization does not suppress awareness that the actual post-exilic community faced ongoing challenges to maintain the purity and integrity that the organizational template assumed.</p>",
    "23": "<p>The sixteenth lot to Hananiah (from Heman&rsquo;s sons, v4) — meaning &lsquo;YHWH has been gracious.&rsquo; This is one of the most common names in the OT, borne by dozens of figures including the prophet who disputed with Jeremiah (Jer 28), the Babylonian companion of Daniel (Dan 1:6, renamed Shadrach), and numerous post-exilic Levites. The prevalence of the name reflects the post-exilic community&rsquo;s theological emphasis on divine grace as the foundational category for understanding their survival and restoration after the catastrophe of exile.</p>",
    "24": "<p>The seventeenth lot to Joshbekashah (from Heman&rsquo;s sons, v4) — a unique name that appears only in this list. Its meaning is uncertain; possibly related to &lsquo;dwelling in hardship&rsquo; or &lsquo;sitting in difficult places.&rsquo; If the embedded prayer hypothesis for Heman&rsquo;s sons&rsquo; names (see v4 commentary) is correct, <em>yôšbᵉqāšāh</em> would be part of the petition &lsquo;I dwell in hardship&rsquo; or &lsquo;I sit in a hard/difficult place&rsquo; — a statement of distress within a prayer for divine help. Whatever its etymology, the name&rsquo;s uniqueness to this list marks it as a genuine archival name rather than a theological construct of the Chronicler.</p>",
    "25": "<p>The eighteenth lot to Hanani (from Heman&rsquo;s sons, v4) — a shortened form of Hananiah (&lsquo;YHWH has been gracious&rsquo;). A Hanani is the brother of Nehemiah (Neh 1:2; 7:2) who brought news of Jerusalem&rsquo;s desolation from Judah — the report that prompted Nehemiah&rsquo;s prayer and ultimately his return to rebuild Jerusalem&rsquo;s walls. Whether this Hanani is related to the musical course of the same name is unknown; the name was common. Another Hanani appears as a seer who confronted King Asa of Judah (2 Chr 16:7) and was imprisoned for it — a prophetic role consistent with the prophetic character of Levitical music described in v1.</p>",
    "26": "<p>The nineteenth lot to Mallothi (from Heman&rsquo;s sons, v4) — a name meaning possibly &lsquo;I have spoken&rsquo; or &lsquo;utterance.&rsquo; The verb root <em>mlh</em> or <em>ml</em> (to speak, utter) would make the name a fitting designation for a temple singer whose primary function is to speak/sing God&rsquo;s praise. If this etymology is correct, Mallothi&rsquo;s name is itself a vocational statement: the singer&rsquo;s identity is bound up with his speaking/singing function. The name appears only in this list, reinforcing its character as a genuine archival name from the Davidic musical organization.</p>",
    "27": "<p>The twentieth lot to Eliathah (from Heman&rsquo;s sons, v4) — meaning &lsquo;God has come&rsquo; or &lsquo;God is.&rsquo; The theophanic meaning of the name aligns with the theological purpose of temple music: to create an encounter with the God who comes, who is present among his people. The temple musicians&rsquo; prophetic function (v1) is precisely to mediate God&rsquo;s presence through song. A name meaning &lsquo;God has come&rsquo; for a temple singer thus articulates the very purpose of his vocation. This kind of alignment between name and function may reflect the naming practices of Levitical families who gave their children names that expressed the theological vision of their hereditary calling.</p>",
    "28": "<p>The twenty-first lot to Hothir (from Heman&rsquo;s sons, v4) — meaning &lsquo;abundance&rsquo; or &lsquo;he has made abundant.&rsquo; The name appears only in this list. The sense of abundance that the name carries resonates with the Chronicler&rsquo;s picture of the Davidic era as a time of exceptional provision for the temple: abundant Levites (38,000), abundant musicians (288), abundant materials for the temple (1 Chr 22:14). Hothir&rsquo;s name within Heman&rsquo;s list participates in this theology of divine abundance — YHWH provides not merely sufficiently but lavishly for the service of his house.</p>",
    "29": "<p>The twenty-second lot to Giddalti (from Heman&rsquo;s sons, v4) — meaning &lsquo;I have magnified&rsquo; or &lsquo;I have brought up greatly.&rsquo; The verb <em>giḏḏal</em> (to make great, to magnify) appears in doxological contexts throughout the Psalter (Ps 34:3: <em>gaḏḏᵉlû laYHWH ʾittî</em>, &lsquo;magnify YHWH with me&rsquo;; Ps 69:30: &lsquo;I will magnify him with thanksgiving&rsquo;). A temple singer named &lsquo;I have magnified&rsquo; embodies in his name the primary act of his vocation: the magnification of YHWH through song. The congregation that sings Ps 34 with a singer named Giddalti is in some sense performing its own commentary on his name.</p>",
    "30": "<p>The twenty-third lot to Mahazioth (from Heman&rsquo;s sons, v4) — meaning possibly &lsquo;visions&rsquo; (from <em>ḥāzôṯ</em>, plural of vision). If correct, the name situates this Hemanite singer within the prophetic-visionary dimension of temple music: Heman is the &lsquo;king&rsquo;s seer&rsquo; (v5), and his son named &lsquo;visions&rsquo; carries that visionary identity into the next generation. The connection between musical performance and prophetic vision appears throughout the prophetic literature: Elisha calls for a musician before the prophetic word comes (2 Kgs 3:15: <em>wᵉhāyāh kᵉnaggen hamnaggen wattᵉhî ʿālāyw yad YHWH</em>), suggesting that music opened the prophetic channel.</p>",
    "31": "<p>The twenty-fourth and final lot to Romamtiezer (from Heman&rsquo;s sons, v4) — meaning &lsquo;I have exalted my helper&rsquo; or &lsquo;exaltation of help.&rsquo; The root <em>rwm</em> (to be high, to exalt) combined with <em>ʿezer</em> (help) makes a name that is both a confession (<em>YHWH is my exalted help</em>) and a doxology. As the final course in the 24-division cycle, Romamtiezer closes the annual rotation with a name that summarizes what all 288 singers do: exalt YHWH who is their help. The concluding position of a name meaning &lsquo;exaltation of help&rsquo; in a list of temple singers gives the 24-course system a doxological ending that functions as the cycle&rsquo;s implicit benediction.</p>"
  }
}

data = load_comm('mkt-context', '1chronicles')
merge_comm(data, NEW)
save_comm('mkt-context', '1chronicles', data)

import json as _json
inter_p = ROOT / 'data' / 'interlinear' / '1chronicles.json'
inter = _json.loads(inter_p.read_text())
for ch in ['23', '24', '25']:
    inter_vs = set(inter.get(ch, {}).keys())
    comm_vs = set(data.get(ch, {}).keys())
    missing = inter_vs - comm_vs
    print(f'  ch{ch}: {len(comm_vs)} verses complete')
    if missing:
        print(f'    MISSING: {sorted(missing, key=int)}')

covered = sum(1 for ch in inter if set(inter[ch].keys()) <= set(data.get(ch, {}).keys()))
print(f'1 Chron context: {covered}/{len(inter)} chapters complete')
print('1 Chronicles context fill (chs 23–25) done.')
